const parent = document.getElementById('viz');
const host = document.createElement('div'); host.style.cssText='display:block;width:100%';
const root = host.attachShadow({mode:'open'});
const CSS = `
:host{display:block;width:100%;--_bg:var(--ov-bg,#fff);--_raised:var(--ov-bg,#fff);--_text:var(--ov-text,#1f2933);--_muted:var(--ov-muted,#6b7280);--_line:var(--ov-line,#e5e7eb);--_accent:var(--ov-accent,#4f46e5);--_ok:var(--ov-ok,#0f9d58);--_no:var(--ov-no,#e11d48);--_partial:var(--ov-partial,#d97706);--_soft:#f8fafc;--_group:#f3f4f6;--_accent-soft:#eef2ff;--_hover:#f8fafc;color:var(--_text);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;-webkit-font-smoothing:antialiased}
:host([hidden]){display:none}
*{box-sizing:border-box}
button{font:inherit}
.sr-only{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}

.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.heading{padding:22px 24px 18px;border-bottom:1px solid var(--_line);background:var(--_soft)}
.eyebrow{margin:0 0 6px;color:var(--_accent);font-size:11px;font-weight:800;letter-spacing:.13em;text-transform:uppercase}
h2{margin:0;color:var(--_text);font-size:clamp(20px,3vw,27px);font-weight:750;letter-spacing:-.025em;line-height:1.2}
.subtitle{margin-top:7px;color:var(--_muted);font-size:13px;line-height:1.45}
.feed{max-height:620px;overflow:auto;overscroll-behavior:contain;scrollbar-color:var(--_line) transparent}
.item{position:relative;display:grid;grid-template-columns:42px minmax(0,1fr) auto;gap:13px;padding:18px 24px}
.item+.item{border-top:1px solid var(--_line)}
.item:hover{background:var(--_hover)}
.avatar-wrap{position:relative}
.avatar{display:flex;width:40px;height:40px;align-items:center;justify-content:center;border:1px solid var(--_line);border-radius:13px;background:var(--_accent-soft);color:var(--_accent);font-size:12px;font-weight:850;letter-spacing:.02em}
.dot{position:absolute;right:-2px;bottom:-2px;width:11px;height:11px;border:2px solid var(--_bg);border-radius:50%;background:var(--_accent)}
.dot.positive{background:var(--_ok)}.dot.warning{background:var(--_partial)}.dot.negative{background:var(--_no)}
.sentence{padding-top:1px;color:var(--_text);font-size:13px;line-height:1.5}
.sentence strong{font-weight:780}.target{color:var(--_accent)}
.detail{margin-top:5px;color:var(--_muted);font-size:12px;line-height:1.45}
time{padding-top:3px;color:var(--_muted);font-size:11px;font-weight:650;white-space:nowrap;font-variant-numeric:tabular-nums}
.empty{padding:42px 24px;color:var(--_muted);font-size:14px;text-align:center}
@media (max-width:560px){.heading{padding:18px}.item{grid-template-columns:38px minmax(0,1fr);gap:11px;padding:16px 18px}.avatar{width:36px;height:36px;border-radius:12px}time{grid-column:2;padding-top:0}.sentence{padding-top:0}}

@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];

const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Recent activity';
const input=Array.isArray(data.items)?data.items:[]; const nowRaw=Date.parse(data.now); const now=Number.isFinite(nowRaw)?nowRaw:Date.now();
const items=input.map((item,index)=>({item,index,time:Date.parse(item&&item.at)})).sort((a,b)=>{
  const at=Number.isFinite(a.time)?a.time:-Infinity; const bt=Number.isFinite(b.time)?b.time:-Infinity; return bt-at||a.index-b.index;
});
const relative=(timestamp)=>{
  if(!Number.isFinite(timestamp)) return 'Time unknown'; const delta=Math.round((now-timestamp)/1000); const future=delta<0; const seconds=Math.abs(delta);
  if(seconds<45) return future?'in moments':'just now';
  const units=seconds<3600?[Math.round(seconds/60),'min']:seconds<86400?[Math.round(seconds/3600),'hr']:seconds<604800?[Math.round(seconds/86400),'day']:seconds<2629800?[Math.round(seconds/604800),'wk']:seconds<31557600?[Math.round(seconds/2629800),'mo']:[Math.round(seconds/31557600),'yr'];
  return future?'in '+units[0]+' '+units[1]+' ago'.replace(' ago',''):units[0]+' '+units[1]+' ago';
};
const initials=(actor,avatar)=>{
  if(typeof avatar==='string'&&avatar.trim()) return avatar.trim().slice(0,3);
  return String(actor||'?').trim().split(/\s+/).slice(0,2).map((part)=>part[0]||'').join('').toUpperCase()||'?';
};
const frame=make('section','frame'); frame.setAttribute('aria-label',title); const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','Activity')); heading.appendChild(make('h2','',title)); if(data.subtitle) heading.appendChild(make('div','subtitle',String(data.subtitle))); frame.appendChild(heading);
if(!items.length){ frame.appendChild(make('div','empty','No activity to show yet.')); }
else{
  const feed=make('div','feed'); feed.setAttribute('role','feed');
  items.forEach(({item,time})=>{
    const tone=item&&['positive','warning','negative','neutral'].includes(item.tone)?item.tone:'neutral'; const article=make('article','item'); article.setAttribute('aria-label',(item&&item.actor?String(item.actor):'Someone')+' '+(item&&item.action?String(item.action):'updated'));
    const avatarWrap=make('div','avatar-wrap'); avatarWrap.appendChild(make('div','avatar',initials(item&&item.actor,item&&item.avatar))); avatarWrap.appendChild(make('span','dot'+(tone==='neutral'?'':' '+tone))); article.appendChild(avatarWrap);
    const copy=make('div'); const sentence=make('div','sentence'); sentence.appendChild(make('strong','',item&&item.actor?String(item.actor):'Someone')); sentence.appendChild(document.createTextNode(' '+(item&&item.action?String(item.action):'updated')));
    if(item&&item.target){ sentence.appendChild(document.createTextNode(' ')); sentence.appendChild(make('strong','target',String(item.target))); } copy.appendChild(sentence);
    if(item&&item.detail) copy.appendChild(make('div','detail',String(item.detail))); article.appendChild(copy);
    const timeNode=make('time','',relative(time)); if(item&&item.at) timeNode.dateTime=String(item.at); article.appendChild(timeNode); feed.appendChild(article);
  });
  frame.appendChild(feed);
